var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>침식파를 동반한 모래 폭풍이 소멸하였음을 알려드립니다. </color>","JPN":"<color=#ffd34c>侵食波を伴う、砂嵐が消滅したことをお知らせいたします。</color>","ENG":"<color=#ffd34c>The sandstorm accompanied by the Corruption rays has been dissipated.</color>","TWN":"<color=#ffd34c>通知，挾帶侵蝕波的沙塵暴已消失。</color>"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>금일, 기상 조절기는 폭풍 없이 맑은 날씨를 유지할 예정입니다. </color>","JPN":"<color=#ffd34c>本日、気象調節器は嵐も起こることなく、ずっと晴れを維持する予定です。</color>","ENG":"<color=#ffd34c>The weather controller expects clear skies without any sandstorm for today.</color>","TWN":"<color=#ffd34c>今日，氣候調節器預計將保持晴朗天氣，沒有風暴。</color>"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>다시 한번 알려드립니다……. </color>","JPN":"<color=#ffd34c>繰り返します……</color>","ENG":"<color=#ffd34c>Once again...</color>","TWN":"<color=#ffd34c>重複一遍……</color>"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"아직 못 찾았나요?","JPN":"まだ見つかっていないのですか？","ENG":"Haven't you found them yet?","TWN":"還沒找到人嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"워낙에 신출귀몰해서 수색이 어렵습니다.","JPN":"神出鬼没すぎて、捜索に手こずっています。","ENG":"They are like ghosts, so it's difficult to find them.","TWN":"那幾個人神出鬼沒的，很難找。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"발견했다 싶으면 좌표를 왜곡해서 달아나니…… 쉽지 않군요.","JPN":"見つけたと思ったら座標を歪ませて逃げますし……手ごわいですね。","ENG":"Even if I do find them, they distort the coordinates and flee... This will take some time.","TWN":"就算發現到，她們也會扭曲座標逃跑……不太容易。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"하아…… 위에선 토벌한 침식체와 관련된 인물에 대한 정보를 요구하고 있어요.","JPN":"はあ……上層部からは討伐した侵食体と関係のある人物の情報を要求しています。","ENG":"*Sigh* The higher-ups are asking for information about the people related to the extermination of the C.O.","TWN":"哀哀……上面要求提供討伐侵蝕體相關人物的資料。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"잔해 회수엔 시간이 걸리고, 토벌한 카운터에 대한 정보라도 얻으려는 것 같은데…….","JPN":"残骸の回収には時間がかかり、討伐したカウンターの情報でも手に入れようとしているようですが……","ENG":"Since collecting the C.O.'s remains will take time, I think they're trying to obtain information on the Counter that killed it, but...","TWN":"回收侵蝕體殘骸需要時間，似乎是想透過討伐者獲取情報……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"아무튼, 최대한 협조를 구해보도록 해요.","JPN":"とにかく、関係者の皆さんに協力をお願いしてみましょう。","ENG":"Anyway, let's try to get as much cooperation as possible.","TWN":"不管怎樣，讓我們盡可能與他們合作。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"죄송하지만, 조금 더 고생해주세요.","JPN":"こんなこと言うのも悪いですが、もう少し頑張ってくださいね。","ENG":"I'm sorry to ask, but please try a little harder.","TWN":"對不起，請再多辛苦一下。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"……갔어요.","JPN":"……行きました。","ENG":"...They're gone.","TWN":"……走咧。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"휘유! 들키는 줄 알았네!","JPN":"ふう！　バレるかと思った！","ENG":"Phew! I thought we were going to get caught!","TWN":"呼！幸好沒被發現！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"전대장님! 구태여 여기 숨어있을 필요가 있나요?","JPN":"戦隊長！　ここに隠れている必要ありますか？","ENG":"Commander! Do we really need to keep hiding from them?","TWN":"戰隊長！真的有必要藏在這裡嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"맞아요. 그냥 <color=#ffd34c>내가 구 관리국의 전대장이다! </color> 라고 한마디만 하시면…….","JPN":"そうですよ。別に<color=#ffd34c>私が旧管理局の戦隊長だ！</color>って一言言えば……","ENG":"She's right. If you just say, <color=#ffd34c>\\"I am a former Commander of the Old Administration!\\"</color>","TWN":"沒錯。只要你說一句，<color=#ffd34c>我是舊管理局的戰隊長！</color>……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"지금 정체를 드러낼 생각은 없다.","JPN":"今正体を現すつもりはない。","ENG":"I have no intention of revealing my identity at this moment.","TWN":"現在還不是暴露身份的時候。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그저 오래전 끝내야 했던 임무를 마친 것뿐이니까.","JPN":"かつて果たせなかった任務を、やっと終わらせただけだからな。","ENG":"All I have done is merely complete a mission long overdue.","TWN":"我只是完成很久以前就該完成的任務而已。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"게다가 나는 아직 지금의 관리국에 대한 정보가 부족해.","JPN":"それに、私はまだ今の管理局の情報が足りない。","ENG":"Also, I lack information on the current Administration.","TWN":"而且對現在的管理局還缺乏足夠的資訊。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"하긴……지금의 관리국은 구 관리국과 태도가 다를 수도 있겠어요.","JPN":"確かに……今の管理局は旧管理局とは違う態度を取られるかもしれません。","ENG":"I guess you're right... The current Administration might have a different attitude from the Old Administration.","TWN":"確實……現在的管理局可能和舊管理局的態度不同。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"급한 것도 아니니까! 천천히 생각하도록 하죠!","JPN":"急用でもないですし！　ゆっくり考えましょう！","ENG":"And we're in no hurry! So, let's take our time and think about it!","TWN":"也不急！那就慢慢想吧！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"그나저나 전대장님. 동결되어 있었다는 건 무슨 얘기죠?","JPN":"それより戦隊長。凍結されていたというのはどういうことですか？","ENG":"Anyway, Commander. Why were you in cryogenic sleep?","TWN":"話說回來，戰隊長，膠囊又是怎麼回事？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"작전이 실패한 후, 도착한 카멜롯은 정신을 잃은 나를 구출했다.","JPN":"作戦が失敗した後、到着したキャメロットは気を失っていた私を救出した。","ENG":"After the operation failed, Camelot arrived and rescued me while I was unconscious.","TWN":"作戰失敗後，趕到的卡梅羅救出昏迷的我。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"하지만 테라브레인으로부터 작전 수행 불가 판정을 받았지.","JPN":"だが、テラブレインから作戦遂行不可と判定されてな。","ENG":"But Terrabrain deemed that the operation was impossible to be carried out.","TWN":"但是特拉大腦判斷我無法繼續執行作戰。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"말소된 정보는 복구한 모양이지만, 내 부상은 당장 해결할 수 없는 수준이었어.","JPN":"抹消された情報は何とか復元できたようだが、私の怪我はすぐに治せるレベルではなかった。","ENG":"I think they've restored the erased information, but my injuries were at a level that couldn't be treated immediately.","TWN":"雖然似乎已經復原被抹除的記錄，但我的傷勢當下無法立刻處理好。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"결국 테라브레인은 내가 회복될 때까지 동결하기로 결정했다.","JPN":"結局テラブレインは私が回復するまで凍結させると決めた。","ENG":"Ultimately, Terrabrain decided to put me into cryogenic sleep until I fully recovered.","TWN":"最後，特拉大腦就決定在我恢復之前把我冰封起來。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"물론, 나를 깨워야 했던 관리국이 먼저 무너져 내릴 줄은 몰랐지만.","JPN":"もちろん、私を起こすべき管理局が先に崩壊するとは思っていなかったのだろうがな。","ENG":"Of course, no one knew that the Administration that was supposed to wake me up would collapse first.","TWN":"只是沒想到在叫醒我之前管理局會先瓦解。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};